SELECT 
FROM sys_sensor_data
WHERE deviceId = #{deviceId}
    AND createTime >= #{startTime}
    AND createTime <= #{endTime}
ORDER BY createTime DESC

SELECT s1.* FROM sys_sensor_data s1 INNER JOIN ( SELECT deviceId, MAX(createTime) AS maxTime FROM sys_sensor_data WHERE deviceId IN
#{id}
GROUP BY deviceId ) s2 ON s1.deviceId = s2.deviceId AND s1.createTime = s2.maxTime
